                    {"type": "quiz", "question": "Сколько времени спринта рекомендуется тратить на Backlog Grooming?", "options": [{"id": "a", "text": "1-2%", "correct": False}, {"id": "b", "text": "5-10%", "correct": True}, {"id": "c", "text": "30-40%", "correct": False}, {"id": "d", "text": "50%", "correct": False}]},
