                    {"type": "quiz", "question": "Что такое Growth Loop?", "options": [{"id": "a", "text": "Линейная воронка продаж", "correct": False}, {"id": "b", "text": "Циклический процесс: пользователь привлекает нового", "correct": True}, {"id": "c", "text": "Ежемесячный отчёт о росте", "correct": False}, {"id": "d", "text": "Инструмент аналитики", "correct": False}]},
